this is code
```
typedef enum {low,mid,high} AddrType;

class MyBus;
    rand AddrType atype;

    constraint addr_range
    {
      (actype == low ) -> addr inside {[0  :15] };
      (actype == mid ) -> addr inside {[16 :127]};
      (actype == high) -> addr inside {[128:255]};
    }
endclass : MyBus

program tb;
    MyBus bus;

    initial begin
        bus = new;
    end
endprogram : tb
```
makefile:
```
all: clean build run

build:
    verilator -sv --binary -j 0 -Wall tb.sv
run:
    ./obj_dir/Vtb
clean:
    rm -rf ./obj_dir
```

